sql_query:
SELECT "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Prostate' AND "Class of ICI" = 'PD-L1' AND "Included in MA" = 'Yes';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Name of ICI" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Prostate' AND "Class of ICI" = 'PD-L1' AND "Included in MA" = 'Yes'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_ici_brand_name(source_value) AS "brand_name"
FROM base;
